import React, { useState, useEffect, useRef } from 'react';
import { Preloader } from './Preloader';

export const Hero: React.FC = () => {
  const [isLoading, setIsLoading] = useState(true);
  const [showPreloader, setShowPreloader] = useState(true);
  const [progress, setProgress] = useState(0);
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    // Simulate initial progress to avoid static 0%
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 95) return prev;
        // Random small increments to simulate network activity
        return prev + Math.random() * 15;
      });
    }, 400);

    // If video is already cached/ready
    if (videoRef.current && videoRef.current.readyState >= 3) {
      handleVideoLoad();
    }

    return () => clearInterval(interval);
  }, []);

  const handleVideoLoad = () => {
    setProgress(100);
    // Slight delay to let user see 100% before fading out
    setTimeout(() => {
      setIsLoading(false);
      // Remove from DOM after fade transition completes
      setTimeout(() => {
        setShowPreloader(false);
      }, 1000);
    }, 600);
  };

  return (
    <section className="relative h-screen w-full overflow-hidden flex items-center justify-center">

      {/* Preloader Overlay */}
      {showPreloader && (
        <div className={`fixed inset-0 z-[100] bg-[#0a0a0a] transition-opacity duration-1000 ease-in-out ${isLoading ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
          <Preloader progress={progress} />
        </div>
      )}

      {/* Background Video - Above Grain (z-40) */}
      <div className="absolute inset-0 z-40">
        <video 
          ref={videoRef}
          src="https://firebasestorage.googleapis.com/v0/b/redhead-productions.firebasestorage.app/o/Grain%20Showreel%204.mp4?alt=media&token=23106ecd-3296-4fda-ae73-186140b9e720" 
          autoPlay 
          loop 
          muted 
          playsInline
          onCanPlayThrough={handleVideoLoad}
          className="w-full h-full object-cover opacity-60"
        />
        <div className="absolute inset-0 bg-gradient-to-b from-black/20 via-transparent to-[#0a0a0a]" />
      </div>

      {/* Hero Content - Above Video (z-50) */}
      <div className={`relative z-50 text-center flex flex-col items-center transition-all duration-1000 delay-500 ${isLoading ? 'opacity-0 translate-y-10' : 'opacity-100 translate-y-0'}`}>
        <h1 className="text-[15vw] leading-[0.9] font-display font-medium uppercase tracking-tight mix-blend-overlay text-white opacity-90">
          Grain.
        </h1>

        <div className="mt-12 flex flex-col md:flex-row gap-4 md:gap-24 text-xs md:text-sm font-medium tracking-wide text-white/80 uppercase items-center">
          <span>Mini films that sell</span>
          <span className="hidden md:inline">•</span>
          <span>{new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
        </div>
      </div>

      <div className={`absolute bottom-12 right-12 z-50 text-xs text-white/40 uppercase tracking-widest animate-pulse transition-opacity duration-1000 delay-1000 ${isLoading ? 'opacity-0' : 'opacity-100'}`}>
        Scroll to Explore
      </div>
    </section>
  );
};

import React, { useEffect, useRef } from 'react';

export const GrainOverlay: React.FC = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrameId: number;

    // Generate a noise pattern on an offscreen canvas
    const patternSize = 256;
    const patternCanvas = document.createElement('canvas');
    patternCanvas.width = patternSize;
    patternCanvas.height = patternSize;
    const pCtx = patternCanvas.getContext('2d');

    if (pCtx) {
        const pData = pCtx.createImageData(patternSize, patternSize);
        const buffer = new Uint32Array(pData.data.buffer);
        const len = buffer.length;

        for (let i = 0; i < len; i++) {
             const random = Math.random();
             if (random < 0.4) { 
                // White pixel with varying alpha
                const alpha = Math.floor(Math.random() * 20) + 20;
                buffer[i] = (alpha << 24) | 0x00FFFFFF;
             } else {
                buffer[i] = 0;
             }
        }
        pCtx.putImageData(pData, 0, 0);
    }

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };

    window.addEventListener('resize', resize);
    resize();

    const draw = () => {
        if (!ctx) return;
        const xOffset = Math.random() * patternSize;
        const yOffset = Math.random() * patternSize;

        ctx.clearRect(0, 0, canvas.width, canvas.height);

        const pattern = ctx.createPattern(patternCanvas, 'repeat');
        if (pattern) {
            ctx.fillStyle = pattern;
            ctx.save();
            ctx.translate(xOffset, yOffset);
            ctx.fillRect(-patternSize, -patternSize, canvas.width + patternSize, canvas.height + patternSize);
            ctx.restore();
        }

        animationFrameId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed inset-0 w-full h-full pointer-events-none z-[120] opacity-30"
    />
  );
};
